parameters.prompt:
=# Impact Evaluation Task

## Project Information:
{{JSON.stringify($json.body.projectInfo, null, 2)}}

## Pre-Survey Data:
{{JSON.stringify($json.body.surveyData.preSurvey, null, 2)}}

## Post-Survey Data:
{{JSON.stringify($json.body.surveyData.postSurvey, null, 2)}}

## Indicators:
{{JSON.stringify($json.body.indicators, null, 2)}}

Analyze the impact by:
1. Comparing pre and post survey results
2. Calculating improvement percentages
3. Evaluating significance of changes
4. Providing overall impact score (0-100)
5. Generating actionable recommendations
6. Identifying success factors

## Response Format (JSON):
{
  "impactEvaluation": {
    "overallImpact": 87,
    "improvements": [
      {
        "indicator": "Knowledge Score",
        "improvement": 25.5,
        "significance": "high"
      }
    ],
    "analysis": "Detailed analysis text here..."
  },
  "recommendations": [
    "Recommendation 1",
    "Recommendation 2"
  ],
  "insights": [
    "Key insight 1",
    "Key insight 2"
  ]
}

Provide ONLY the JSON response.

parameters.jsCode:
// Parse LLaMA response and structure data
const llamaResponse = $input.first().json.response;

// Try to parse JSON from response
let parsedData;
try {
  // Extract JSON from markdown code blocks if present
  const jsonMatch = llamaResponse.match(/```json\n([\s\S]*?)\n```/);
  const jsonString = jsonMatch ? jsonMatch[1] : llamaResponse;
  parsedData = JSON.parse(jsonString);
} catch (e) {
  // Fallback if JSON parsing fails
  parsedData = {
    error: 'Failed to parse LLaMA response',
    rawResponse: llamaResponse
  };
}

// Get original request data
const requestData = $('Webhook - Receive Analysis Request').first().json.body;

// Structure final response
const finalResponse = {
  success: true,
  data: {
    textAnalysis: parsedData.sentiment ? {
      sentiment: parsedData.sentiment,
      sentimentScore: parsedData.sentimentScore,
      confidence: parsedData.confidence,
      keywords: parsedData.keywords || [],
      entities: parsedData.entities || [],
      emotions: parsedData.emotions,
      summary: parsedData.summary,
      themes: parsedData.themes || []
    } : undefined,

    topics: parsedData.topics || [],

    impactEvaluation: parsedData.impactEvaluation,

    recommendations: parsedData.recommendations || [],

    insights: parsedData.insights || []
  },
  metadata: {
    processingTime: Date.now() - $('Webhook - Receive Analysis Request').first().json.timestamp || 0,
    model: 'llama3:70b',
    timestamp: new Date().toISOString(),
    projectId: requestData.projectInfo?.id,
    analysisType: requestData.analysisType
  }
};

return finalResponse;
